import { MakeLogicType, kea, path, props, selectors } from 'kea'

import { Scene } from 'scenes/sceneTypes'
import { urls } from 'scenes/urls'

import { SIDE_PANEL_CONTEXT_KEY, SidePanelSceneContext } from '~/layout/navigation-3000/sidepanel/types'
import { cohortsModel } from '~/models/cohortsModel'
import { ActivityScope, Breadcrumb, ProjectTreeRef } from '~/types'

import { CohortLogicProps } from './cohortEditLogic'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface cohortSceneLogicValues {
    breadcrumbs: Breadcrumb[];
    projectTreeRef: ProjectTreeRef;
    sidePanelContext: SidePanelSceneContext | null;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface cohortSceneLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        breadcrumbs: (cohortsById: Partial<Record<number | string, import("~/types").CohortType>>, arg: CohortLogicProps["id"]) => Breadcrumb[];
        sidePanelContext: (arg: number | "new" | undefined) => SidePanelSceneContext | null;
        projectTreeRef: (arg: number | "new" | undefined) => ProjectTreeRef;
    };
}

export type cohortSceneLogicType = MakeLogicType<cohortSceneLogicValues, {}, CohortLogicProps, cohortSceneLogicMeta>;

export const cohortSceneLogic = kea<cohortSceneLogicType>([
    props({} as CohortLogicProps),
    path(['scenes', 'cohorts', 'cohortLogic']),

    selectors({
        breadcrumbs: [
            () => [cohortsModel.selectors.cohortsById, (_, props) => props.id as CohortLogicProps['id']],
            (cohortsById: Partial<Record<number | string, import("~/types").CohortType>>, cohortId: CohortLogicProps["id"]): Breadcrumb[] => {
                return [
                    {
                        key: 'cohorts',
                        name: 'Cohorts',
                        path: urls.cohorts(),
                        iconType: 'cohort',
                    },
                    {
                        key: [Scene.Cohort, cohortId || 'loading'],
                        name: cohortId && cohortId !== 'new' ? cohortsById[cohortId]?.name || 'Untitled' : 'Untitled',
                        iconType: 'cohort',
                    },
                ]
            },
        ],
        [SIDE_PANEL_CONTEXT_KEY]: [
            () => [(_, props: CohortLogicProps) => props.id],
            (id: CohortLogicProps['id']): SidePanelSceneContext | null => {
                return id && id !== 'new'
                    ? {
                          activity_scope: ActivityScope.COHORT,
                          activity_item_id: `${id}`,
                      }
                    : null
            },
        ],
        projectTreeRef: [
            () => [(_, props: CohortLogicProps) => props.id],
            (id: number | "new" | undefined): ProjectTreeRef => ({ type: 'cohort', ref: id === 'new' ? null : String(id) }),
        ],
    }),
])
